/* globals window, document, CS_CONFIG */
import { handleDocIdInUrl } from './_utils/document-id-in-url.js';
import { randomUserFromAPI } from './_utils/randomuser.js';
import buildUserTokenUrl from './_utils/buildusertokenurl.js';

( async () => {
	const csConfig = CS_CONFIG;
	const channelId = handleDocIdInUrl();

	const randomUser = await randomUserFromAPI();

	csConfig.tokenUrl = buildUserTokenUrl( csConfig.tokenUrl, randomUser );

	const { ClassicEditor, Context, ContextWatchdog } = window;

	const watchdog = new ContextWatchdog( Context );

	// Create a configuration, passing additional configuration options:
	const contextConfiguration = {
		// Configuration for real-time collaboration features, shared between the editors:
		cloudServices: csConfig,
		// Collaboration configuration for the context:
		collaboration: {
			channelId
		}
	};

	await watchdog.create( contextConfiguration );

	for ( const editorElement of document.querySelectorAll( '.editor' ) ) {
		await watchdog.add( {
			id: editorElement.id,
			type: 'editor',
			sourceElementOrData: editorElement,
			config: {
				collaboration: {
					channelId: channelId + '-' + editorElement.id
				},
				ui: {
					viewportOffset: {
						top: window.getViewportTopOffsetConfig()
					}
				},
				mention: {
					feeds: [
						{
							marker: '@',
							feed: [ '@Barney', '@Lily', '@Marry Ann', '@Marshall', '@Robin', '@Ted' ]
						}
					]
				}
			},
			creator: ( element, config ) => ClassicEditor.create( element, config )
		} );
	}
} )();
